import { ExceptionFilter, Catch, ArgumentsHost, HttpException } from '@nestjs/common';
import { Request, Response } from 'express';

@Catch(HttpException)
export class GlobalExceptionFilter implements ExceptionFilter {
  catch(exception: HttpException, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();
    const status = exception.getStatus();
    const exceptionResponse = exception.getResponse();
    const message = typeof exceptionResponse === 'string' ? exceptionResponse : (exceptionResponse as any).message;

    response.status(status).json({
      statusCode: status,
      timestamp: new Date().toISOString(),
      path: request.url,
      message: message || exception.message
    });
  }
}

import { NotFoundException } from '@nestjs/common';

@Get(':id')
async getUser(@Param('id') id: string) {
  const user = await this.userService.findById(id);
  if (!user) {
    throw new NotFoundException(`Utilisateur avec l'id ${id} non trouvé`);
  }
  return user;
}

import { HttpException, HttpStatus } from '@nestjs/common';

export class InsufficientFundsException extends HttpException {
  constructor(message = 'Solde insuffisant pour effectuer ce paiement') {
    super(message, 402); // ou HttpStatus.UNPROCESSABLE_ENTITY (422)
  }
}

async processPayment(amount: number, cardDetails: any) {
  const balance = await this.getBalance();
  if (balance < amount) {
    throw new InsufficientFundsException();
  }
  if (this.isCardExpired(cardDetails)) {
    throw new BadRequestException('Carte bancaire expirée');
  }
  try {
    await this.externalPaymentGateway.charge(amount);
  } catch (err) {
    throw new ServiceUnavailableException('Le service de paiement est temporairement indisponible');
  }
  return { success: true };
}
